(function () {
  function addStyle() { if (document.getElementById('avz-style')) return; var s = document.createElement('style'); s.id = 'avz-style'; s.textContent = '.avz-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.avz-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:12px}.avz-card{padding:12px;border-radius:10px;background:#f8fafc;border:1px solid #e5e7eb}.avz-row{display:flex;gap:5px;flex-wrap:wrap;margin:10px 0}.avz-cell{min-width:30px;height:30px;border-radius:8px;background:#e8f4fd;border:1px solid #bfdbfe;display:flex;align-items:center;justify-content:center}.avz-cell.hot{background:#ffc107;border-color:#f59e0b;font-weight:700}.avz-cell.done{background:#d4edda;border-color:#28a745}.avz-actions{display:flex;gap:6px;flex-wrap:wrap;align-items:center}.avz-actions input{width:64px;padding:7px;border:1px solid #cbd5e1;border-radius:8px}.avz-actions button{padding:8px 10px}.avz-note{padding:8px;border-left:4px solid #007bff;background:#e8f4fd;border-radius:8px;min-height:42px}.avz-bar{width:24px;background:#007bff;border-radius:6px 6px 0 0;display:flex;align-items:flex-end;justify-content:center;color:#fff;font-size:11px}.avz-bars{height:120px;align-items:flex-end}'; document.head.appendChild(s); }
  function cells(arr, hot, done) { return '<div class="avz-row">' + arr.map(function (v, i) { return '<span class="avz-cell' + (hot.indexOf(i) >= 0 ? ' hot' : '') + (done.indexOf(i) >= 0 ? ' done' : '') + '">' + v + '</span>'; }).join('') + '</div>'; }
  function mount(host) { if (!host || host.dataset.avzMounted) return; host.dataset.avzMounted = '1'; addStyle(); var lin = [6, 3, 9, 1, 8, 4, 7, 2], bin = [2, 4, 6, 8, 10, 12, 14, 16], bub0 = [5, 2, 8, 1, 4]; host.innerHTML = '<div class="avz-wrap"><h4>⚙️ Trực quan hóa thuật toán</h4><div class="avz-grid"><div class="avz-card"><strong>Tìm kiếm tuyến tính</strong><div data-larr></div><div class="avz-actions"><label>x <input data-ltarget type="number" value="8"></label><button data-lstep type="button">Bước tiếp</button><button data-lreset type="button">Làm lại</button></div><div data-lnote class="avz-note"></div></div><div class="avz-card"><strong>Tìm kiếm nhị phân</strong><div data-barr></div><div class="avz-actions"><label>x <input data-btarget type="number" value="12"></label><button data-bstep type="button">Bước tiếp</button><button data-breset type="button">Làm lại</button></div><div data-bnote class="avz-note"></div></div><div class="avz-card"><strong>Bubble sort</strong><div data-sarr></div><div class="avz-actions"><button data-sstep type="button">Bước tiếp</button><button data-sreset type="button">Làm lại</button></div><div data-snote class="avz-note"></div></div></div></div>'; var li = 0, bl = 0, br = bin.length - 1, si = 0, sj = 0, bub = bub0.slice(); function drawL(found) { host.querySelector('[data-larr]').innerHTML = cells(lin, li < lin.length ? [li] : [], found ? [li] : []); host.querySelector('[data-lnote]').textContent = li >= lin.length ? 'Không tìm thấy sau ' + lin.length + ' so sánh.' : 'So sánh A[' + li + '] = ' + lin[li] + ' với x.'; }
    function drawB(mid, msg) { var done = []; for (var i = 0; i < bin.length; i++) if (i < bl || i > br) done.push(i); host.querySelector('[data-barr]').innerHTML = cells(bin, mid === null ? [] : [mid], done); host.querySelector('[data-bnote]').textContent = msg || 'Khoảng tìm kiếm: left=' + bl + ', right=' + br + '. mid=floor((left+right)/2).'; }
    function drawS(hot, msg) { host.querySelector('[data-sarr]').innerHTML = '<div class="avz-row avz-bars">' + bub.map(function (v, i) { return '<span class="avz-bar' + (hot.indexOf(i) >= 0 ? ' hot' : '') + '" style="height:' + (20 + v * 10) + 'px">' + v + '</span>'; }).join('') + '</div>'; host.querySelector('[data-snote]').textContent = msg || 'So sánh cặp kề nhau, đổi chỗ nếu sai thứ tự.'; }
    host.querySelector('[data-lstep]').onclick = function () { var t = +host.querySelector('[data-ltarget]').value; if (li >= lin.length) return drawL(false); if (lin[li] === t) { drawL(true); host.querySelector('[data-lnote]').textContent = 'Tìm thấy x tại vị trí ' + li + ' sau ' + (li + 1) + ' so sánh.'; li = lin.length; return; } li++; drawL(false); };
    host.querySelector('[data-lreset]').onclick = function () { li = 0; drawL(false); };
    host.querySelector('[data-bstep]').onclick = function () { var t = +host.querySelector('[data-btarget]').value; if (bl > br) return drawB(null, 'Không tìm thấy. Khoảng rỗng.'); var mid = Math.floor((bl + br) / 2), val = bin[mid]; if (val === t) return drawB(mid, 'mid=' + mid + ', A[mid]=' + val + '. Tìm thấy!'); if (val < t) { drawB(mid, 'mid=' + mid + ', ' + val + ' < ' + t + ' nên bỏ nửa trái.'); bl = mid + 1; } else { drawB(mid, 'mid=' + mid + ', ' + val + ' > ' + t + ' nên bỏ nửa phải.'); br = mid - 1; } };
    host.querySelector('[data-breset]').onclick = function () { bl = 0; br = bin.length - 1; drawB(null); };
    host.querySelector('[data-sstep]').onclick = function () { if (si >= bub.length - 1) return drawS([], 'Mảng đã được sắp tăng dần.'); if (bub[sj] > bub[sj + 1]) { var tmp = bub[sj]; bub[sj] = bub[sj + 1]; bub[sj + 1] = tmp; drawS([sj, sj + 1], 'Đổi chỗ vì ' + bub[sj + 1] + ' > ' + bub[sj] + '.'); } else drawS([sj, sj + 1], 'Không đổi chỗ vì đúng thứ tự.'); sj++; if (sj >= bub.length - 1 - si) { sj = 0; si++; } };
    host.querySelector('[data-sreset]').onclick = function () { bub = bub0.slice(); si = 0; sj = 0; drawS([], 'Bắt đầu bubble sort.'); };
    drawL(false); drawB(null); drawS([], 'Bắt đầu bubble sort.'); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="algorithm-visualization"]').forEach(mount); });
}());
